// Wyciągnij wszystkie komentarze z postów
const posts = $json.data || [];
const allComments = [];

for (const post of posts) {
  const comments = post.comments?.data || [];
  for (const c of comments) {
    allComments.push({
      post_id: post.id,
      post_text: (post.message || '').substring(0, 100),
      comment_id: c.id || '',
      comment_text: c.message || '',
      author: c.from?.name || 'Nieznany',
      author_id: c.from?.id || '',
      created: c.created_time || '',
      likes: c.like_count || 0
    });
  }
}

if (allComments.length === 0) {
  return [{ json: { no_comments: true, count: 0 } }];
}

return [{ json: { comments: allComments, count: allComments.length } }];

