// Parsuj odpowiedź Gemini
const aiText = $json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const originalComments = $('Wyciagnij Komentarze').first().json.comments;

let analysis;
try {
  // Usuń ewentualne markdown backticki
  const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = {
    comments: [],
    stats: { positive: 0, neutral: 0, negative: 0, crisis: 0 },
    alert: false,
    alert_reason: 'Błąd parsowania AI: ' + e.message
  };
}

// Zlicz alerty
const negativeComments = (analysis.comments || []).filter(c => 
  c.sentiment === 'NEGATIVE' || c.sentiment === 'CRISIS'
);

const urgentComments = (analysis.comments || []).filter(c => 
  c.priorytet === 'URGENT' || c.priorytet === 'HIGH'
);

// Wzbogać negatywne komentarze o oryginalne dane
const enrichedNegative = negativeComments.map(nc => {
  const orig = originalComments.find(oc => oc.comment_id === nc.id) || {};
  return { ...nc, author: orig.author, full_text: orig.comment_text, post_text: orig.post_text };
});

return [{
  json: {
    stats: analysis.stats || {},
    alert: analysis.alert || urgentComments.length > 0,
    alert_reason: analysis.alert_reason,
    negative_count: negativeComments.length,
    urgent_count: urgentComments.length,
    total_analyzed: (analysis.comments || []).length,
    negative_comments: enrichedNegative,
    timestamp: new Date().toISOString()
  }
}];

